diff --git a/hibernate-core/src/main/java/org/hibernate/sql/ast/spi/CorrelationChecker.java b/hibernate-core/src/main/java/org/hibernate/sql/ast/spi/CorrelationChecker.java
new file mode 100644
index 0000000000..1919dbb137
--- /dev/null
+++ b/hibernate-core/src/main/java/org/hibernate/sql/ast/spi/CorrelationChecker.java
@@ -0,0 +1,85 @@
+/*
+ * SPDX-License-Identifier: Apache-2.0
+ * Copyright Red Hat Inc. and Hibernate Authors
+ */
+package org.hibernate.sql.ast.spi;
+
+import org.hibernate.sql.ast.tree.MutationStatement;
+import org.hibernate.sql.ast.tree.SqlAstNode;
+import org.hibernate.sql.ast.tree.delete.DeleteStatement;
+import org.hibernate.sql.ast.tree.expression.ColumnReference;
+import org.hibernate.sql.ast.tree.select.QuerySpec;
+import org.hibernate.sql.ast.tree.update.UpdateStatement;
+
+/**
+ * A walker that checks if a SQL AST node contains a subquery that references a specific table alias.
+ *
+ * @author Yoobin Yoon
+ */
+public class CorrelationChecker extends AbstractSqlAstWalker {
+
+	private final String targetAlias;
+	private boolean inSubquery = false;
+
+	private static class CorrelationException extends RuntimeException {
+		@Override
+		public Throwable fillInStackTrace() {
+			return this;
+		}
+	}
+
+	public static boolean hasCorrelation(SqlAstNode node, String targetAlias) {
+		try {
+			node.accept( new CorrelationChecker( targetAlias ) );
+			return false;
+		}
+		catch (CorrelationException ex) {
+			return true;
+		}
+	}
+
+	public static boolean hasCorrelation(MutationStatement statement, String targetAlias) {
+		try {
+			if ( statement instanceof DeleteStatement deleteStatement ) {
+				if ( deleteStatement.getRestriction() != null ) {
+					deleteStatement.getRestriction().accept( new CorrelationChecker( targetAlias ) );
+				}
+			}
+			else if ( statement instanceof UpdateStatement updateStatement ) {
+				final CorrelationChecker visitor = new CorrelationChecker( targetAlias );
+				if ( updateStatement.getAssignments() != null ) {
+					for ( var assignment : updateStatement.getAssignments() ) {
+						assignment.getAssignedValue().accept( visitor );
+					}
+				}
+				if ( updateStatement.getRestriction() != null ) {
+					updateStatement.getRestriction().accept( visitor );
+				}
+			}
+			return false;
+		}
+		catch (CorrelationException ex) {
+			return true;
+		}
+	}
+
+	private CorrelationChecker(String targetAlias) {
+		this.targetAlias = targetAlias;
+	}
+
+	@Override
+	public void visitQuerySpec(QuerySpec querySpec) {
+		boolean wasInSubquery = inSubquery;
+		inSubquery = true;
+		super.visitQuerySpec( querySpec );
+		inSubquery = wasInSubquery;
+	}
+
+	@Override
+	public void visitColumnReference(ColumnReference columnReference) {
+		if ( inSubquery && targetAlias.equals( columnReference.getQualifier() ) ) {
+			throw new CorrelationException();
+		}
+		super.visitColumnReference( columnReference );
+	}
+}
diff --git a/hibernate-core/src/main/java/org/hibernate/sql/ast/spi/NestedCorrelationChecker.java b/hibernate-core/src/main/java/org/hibernate/sql/ast/spi/NestedCorrelationChecker.java
new file mode 100644
index 0000000000..4952fe8bf0
--- /dev/null
+++ b/hibernate-core/src/main/java/org/hibernate/sql/ast/spi/NestedCorrelationChecker.java
@@ -0,0 +1,76 @@
+/*
+ * SPDX-License-Identifier: Apache-2.0
+ * Copyright Red Hat Inc. and Hibernate Authors
+ */
+package org.hibernate.sql.ast.spi;
+
+import java.util.ArrayList;
+import java.util.HashSet;
+import java.util.List;
+import java.util.Set;
+
+import org.hibernate.sql.ast.tree.SqlAstNode;
+import org.hibernate.sql.ast.tree.expression.ColumnReference;
+import org.hibernate.sql.ast.tree.select.QuerySpec;
+
+/**
+ * A walker that detects nested correlation where a deeper subquery references
+ * an intermediate subquery's table alias.
+ *
+ * @author Yoobin Yoon
+ */
+public class NestedCorrelationChecker extends AbstractSqlAstWalker {
+
+	private final Set<String> currentAliases = new HashSet<>();
+	protected List<String> currentLevelAliases;
+
+	protected static class NestedCorrelationException extends RuntimeException {
+		@Override
+		public Throwable fillInStackTrace() {
+			return this;
+		}
+	}
+
+	public static boolean hasNestedCorrelation(SqlAstNode node) {
+		try {
+			node.accept( new NestedCorrelationChecker() );
+			return false;
+		}
+		catch (NestedCorrelationException ex) {
+			return true;
+		}
+	}
+
+	@Override
+	public void visitQuerySpec(QuerySpec querySpec) {
+		if ( currentLevelAliases != null ) {
+			currentAliases.addAll( currentLevelAliases );
+		}
+		List<String> aliases = new ArrayList<>();
+		if ( querySpec.getFromClause() != null ) {
+			querySpec.getFromClause().visitTableReferences( tableReference -> {
+				String alias = tableReference.getIdentificationVariable();
+				if ( alias != null && !currentAliases.contains( alias ) ) {
+					aliases.add( alias );
+				}
+			} );
+		}
+
+		List<String> previousLevelAliases = currentLevelAliases;
+		currentLevelAliases = aliases;
+		super.visitQuerySpec( querySpec );
+		currentLevelAliases = previousLevelAliases;
+		if ( previousLevelAliases != null ) {
+			currentAliases.removeAll( previousLevelAliases );
+		}
+	}
+
+	@Override
+	public void visitColumnReference(ColumnReference columnReference) {
+		String qualifier = columnReference.getQualifier();
+		if ( qualifier != null && currentAliases.contains( qualifier ) ) {
+			throw new NestedCorrelationException();
+		}
+		super.visitColumnReference( columnReference );
+	}
+}
